import React from 'react'

class BodyComponent extends React.Component {
    constructor( props ) {
        super( props )
        this.state = {
            currentPage: "page-home"
        }
        this.displayPage = this.displayPage.bind( this )
    }

    displayPage( page ) {
        this.setState({
            currentPage: page
        })
    }

    render() {
        return <div className="App-body">
            <div className='App-headerMenu App-header'>
                <button className="App-headerButton" onClick={() => this.displayPage('page-home')}>Home</button>
                <button className="App-headerButton" onClick={() => this.displayPage('page-about')}>About</button>
                <button className="App-headerButton" onClick={() => this.displayPage('page-projects')}>Projects</button>
                <button className="App-headerButton" onClick={() => this.displayPage('page-contact')}>Contact</button>
            </div>
            {this.state.currentPage}
        </div>
    }
}

export default BodyComponent